const manifestRows = $items('Read Manifest').map(i => i.json);
const recent = $items('Read Recent Videos').map(i => i.json);
const videosPerRun = $('Globals1').item.json.VIDEOS_PER_RUN || 3;

const eligible = manifestRows.filter(r =>
  r.status === 'active' &&
  Number(r.total_chapters || 0) > Number(r.chapters_covered || 0)
);
if (eligible.length === 0) throw new Error('No eligible books in manifest.');

eligible.sort((a, b) => (a.last_used_at || '').localeCompare(b.last_used_at || ''));

const lookback = $('Globals1').item.json.DEDUP_LOOKBACK || 50;
const recentSorted = recent
  .filter(r => r.created_at)
  .sort((a, b) => (b.created_at).localeCompare(a.created_at))
  .slice(0, lookback);
const dedupContext = recentSorted.map(r => ({ title: r.title || '', summary: r.one_line_summary || '' }));

const picks = [];
let bookIdx = 0, safety = 0;
const used = new Set();
while (picks.length < videosPerRun && safety < 50) {
  safety++;
  const book = eligible[bookIdx % eligible.length];
  const boundaries = JSON.parse(book.chapter_boundaries_json || '[]');
  const covered = Number(book.chapters_covered || 0);
  const nextChapter = boundaries[covered];
  const key = `${book.drive_file_id}:${covered}`;
  if (nextChapter && !used.has(key)) {
    used.add(key);
    picks.push({
      slot: picks.length + 1,
      drive_file_id: book.drive_file_id,
      book_title: book.title,
      book_author: book.author,
      chapter_number: nextChapter.chapter_number,
      chapter_title: nextChapter.chapter_title,
      start_page: nextChapter.start_page,
      end_page: nextChapter.end_page,
      dedup_context: dedupContext
    });
  }
  bookIdx++;
  if (bookIdx > eligible.length * 3) break;
}
if (picks.length === 0) throw new Error('Could not select any chapter for this run.');
return picks.map(p => ({ json: p }));

const raw = $json.text || $json.data || '';
let pages = [];
if (Array.isArray(raw)) pages = raw;
else if (typeof raw === 'string') {
  pages = raw.split('\f');
  if (pages.length < 3) pages = raw.split(/\n\s*\n\s*\n/);
}
const ctx = $('Loop Each Chapter').item.json;
const start = Math.max(0, (ctx.start_page || 1) - 1);
const end = Math.min(pages.length, ctx.end_page || pages.length);
const chapterText = pages.slice(start, end).join('\n\n').slice(0, 25000);
return [{
  json: {
    ...ctx,
    chapter_text: chapterText,
    retry_count: 0,
    avoid_angles: []
  }
}];

const raw = $json.output || '';
const cleaned = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();
let idea;
try { idea = JSON.parse(cleaned); } catch (e) { throw new Error('Dialogue JSON parse failed: ' + e.message); }
if (!Array.isArray(idea.lines) || idea.lines.length < 2) throw new Error('Dialogue must have at least 2 lines');
const ctx = $('Slice To Chapter').item.json;
const fullScript = idea.lines.map(l => l.text).join(' ');
const hook = idea.lines[0].text;
return [{
  json: {
    ...ctx,
    chapter_text: undefined,
    idea_title: idea.title,
    idea_hook: hook,
    idea_one_line_summary: idea.oneLineSummary,
    idea_lines: idea.lines,
    idea_full_script: fullScript,
    idea_on_screen_caption: idea.onScreenCaption,
    idea_viral_score: idea.viralScore,
    idea_selected_angle: idea.selectedAngle,
    idea_keywords: idea.keywords || [],
    idea_word_count: fullScript.split(/\s+/).length
  }
}];

