const raw = $json.output || '';
const cleaned = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();
let dedup;
try { dedup = JSON.parse(cleaned); } catch (e) { dedup = { duplicate: false, similar_to: null, reason: 'parse-failed' }; }
const prev = $('Parse Dialogue').item.json;
const minScore = $('Globals1').item.json.MIN_VIRAL_SCORE || 7;
const maxRetries = $('Globals1').item.json.DEDUP_MAX_RETRIES || 2;
const isDup = dedup.duplicate === true;
const lowScore = Number(prev.idea_viral_score || 0) < minScore;
const needsRetry = (isDup || lowScore) && (prev.retry_count || 0) < maxRetries;
let avoid = Array.isArray(prev.avoid_angles) ? [...prev.avoid_angles] : [];
if (isDup || lowScore) {
  avoid.push({
    title: prev.idea_title,
    summary: prev.idea_one_line_summary,
    reason: isDup ? 'duplicate of ' + (dedup.similar_to || 'past') : 'viral score too low'
  });
}
return [{
  json: {
    ...prev,
    dedup_result: dedup,
    is_duplicate: isDup,
    is_low_score: lowScore,
    needs_retry: needsRetry,
    retry_count: (prev.retry_count || 0) + (needsRetry ? 1 : 0),
    avoid_angles: avoid,
    skip_chapter: (isDup || lowScore) && !needsRetry
  }
}];

// Emit one item per dialogue line for the audio loop
const prev = $json;
const lines = prev.idea_lines || [];
return lines.map((l, i) => ({
  json: {
    _parent: { ...prev, idea_lines: undefined },
    line_index: i,
    speaker: l.speaker,
    text: l.text,
    voice_id: l.speaker === 'A'
      ? $('Globals1').item.json.CHARACTER_A_VOICE_ID
      : $('Globals1').item.json.CHARACTER_B_VOICE_ID
  }
}));

const fs = require('fs');
const path = require('path');
const workDir = $('Globals1').item.json.FFMPEG_WORK_DIR;
if (!fs.existsSync(workDir)) fs.mkdirSync(workDir, { recursive: true });

const res = $json;
if (!res.audio_base64) throw new Error('ElevenLabs returned no audio_base64 for line ' + $('Fan Out Lines').item.json.line_index);

const lineCtx = $('Fan Out Lines').item.json;
const runId = $execution.id || ('r' + Date.now());
const filePath = path.join(workDir, `${runId}_line_${lineCtx.line_index}.mp3`);
fs.writeFileSync(filePath, Buffer.from(res.audio_base64, 'base64'));

const ends = res.alignment?.character_end_times_seconds || [];
const duration = ends.length ? ends[ends.length - 1] : 0;

const chars = res.alignment?.characters || [];
const starts = res.alignment?.character_start_times_seconds || [];
const words = [];
let curWord = '', curStart = null, curEnd = null;
for (let i = 0; i < chars.length; i++) {
  const c = chars[i];
  if (/\s/.test(c) || c === '\n') {
    if (curWord) { words.push({ word: curWord, start: curStart, end: curEnd }); curWord = ''; curStart = null; curEnd = null; }
  } else {
    if (curStart === null) curStart = starts[i];
    curEnd = ends[i];
    curWord += c;
  }
}
if (curWord) words.push({ word: curWord, start: curStart, end: curEnd });

return [{
  json: {
    _parent: lineCtx._parent,
    line_index: lineCtx.line_index,
    speaker: lineCtx.speaker,
    text: lineCtx.text,
    duration,
    word_timings: words,
    audio_path: filePath,
    run_id: runId
  }
}];

// Re-order by line_index, compute offsets, build sprite windows + global word_timings
const fs = require('fs');
const path = require('path');
const arr = ($json.line_index || []).map((idx, i) => ({
  idx,
  speaker: $json.speaker[i],
  text: $json.text[i],
  duration: $json.duration[i],
  words: $json.word_timings[i],
  audio_path: $json.audio_path[i]
}));
arr.sort((a, b) => a.idx - b.idx);

let offset = 0;
const spriteA = [];
const spriteB = [];
const globalWords = [];
for (const line of arr) {
  const winStart = offset;
  const winEnd = offset + line.duration;
  if (line.speaker === 'A') spriteA.push({ start: winStart, end: winEnd });
  else spriteB.push({ start: winStart, end: winEnd });
  for (const w of (line.words || [])) {
    if (w.start == null || w.end == null) continue;
    globalWords.push({ word: w.word, start: offset + w.start, end: offset + w.end, speaker: line.speaker });
  }
  offset += line.duration;
}
const totalDuration = offset;

// Write ffmpeg concat list
const parent = $items('Save Line Audio + Timings')[0].json._parent;
const runId = $items('Save Line Audio + Timings')[0].json.run_id;
const workDir = $('Globals1').item.json.FFMPEG_WORK_DIR;
const listPath = path.join(workDir, `${runId}_concat.txt`);
const listContent = arr.map(l => `file '${l.audio_path.replace(/'/g, "'\\''")}'`).join('\n');
fs.writeFileSync(listPath, listContent);
const mergedPath = path.join(workDir, `${runId}_merged.mp3`);

return [{
  json: {
    ...parent,
    run_id: runId,
    sprite_a_windows: spriteA,
    sprite_b_windows: spriteB,
    word_timings: globalWords,
    total_audio_duration: totalDuration,
    concat_list_path: listPath,
    merged_audio_path: mergedPath,
    lines_ordered: arr
  }
}];

// Read merged audio into binary so we can upload it to Drive
const fs = require('fs');
const prev = $('Compute Timing + Windows').item.json;
const data = fs.readFileSync(prev.merged_audio_path);
return [{
  json: prev,
  binary: {
    audio: {
      data: data.toString('base64'),
      mimeType: 'audio/mpeg',
      fileName: `narration_${prev.run_id}.mp3`
    }
  }
}];

const prev = $('Compute Timing + Windows').item.json;
const fileId = $json.id;
return [{ json: { ...prev, audio_drive_id: fileId, audio_public_url: `https://drive.google.com/uc?export=download&id=${fileId}` } }];

const clips = $items('List Minecraft Clips').map(i => i.json);
if (clips.length === 0) throw new Error('No Minecraft clips found in MINECRAFT_FOOTAGE_FOLDER_ID');
const pick = clips[Math.floor(Math.random() * clips.length)];
const prev = $('Build Audio URL').item.json;
return [{ json: { ...prev, mc_clip_drive_id: pick.id, mc_clip_name: pick.name } }];

const fs = require('fs');
const path = require('path');
const prev = $('Pick Random Clip').item.json;
const workDir = $('Globals1').item.json.FFMPEG_WORK_DIR;
const rawPath = path.join(workDir, `${prev.run_id}_mc_raw.mp4`);
const trimmedPath = path.join(workDir, `${prev.run_id}_mc_trimmed.mp4`);
fs.writeFileSync(rawPath, Buffer.from($binary.data.data, 'base64'));
// Random start offset between 0 and 25s (clips are assumed >60s long)
const startOffset = Math.floor(Math.random() * 25);
const dur = Math.ceil(prev.total_audio_duration + 1);
return [{ json: { ...prev, mc_raw_path: rawPath, mc_trimmed_path: trimmedPath, mc_start_offset: startOffset, mc_duration: dur } }];

const fs = require('fs');
const prev = $('Save Raw + Plan Trim').item.json;
const data = fs.readFileSync(prev.mc_trimmed_path);
return [{
  json: prev,
  binary: {
    data: {
      data: data.toString('base64'),
      mimeType: 'video/mp4',
      fileName: `mc_${prev.run_id}.mp4`
    }
  }
}];

const prev = $('Load Trimmed Clip').item.json;
const fileId = $json.id;
return [{ json: { ...prev, bg_drive_id: fileId, bg_public_url: `https://drive.google.com/uc?export=download&id=${fileId}` } }];

const res = Array.isArray($json) ? $json[0] : $json;
const prev = $('Build BG URL').item.json;
return [{ json: { ...prev, creatomate_render_id: res.id, creatomate_initial_status: res.status, final_video_url: res.url || null } }];

const res = $json;
const prev = $('Capture Render Refs').item.json;
if (!res.url) throw new Error('Creatomate finished but no URL');
return [{ json: { ...prev, final_video_url: res.url, final_video_duration: res.duration || null } }];

