// Approval webhook can pass either query params (?approved=true) or JSON body { approved: true }
const body = $json.body || {};
const query = $json.query || $json.params || {};
const approved = (body.approved === true || body.approve === true || query.approved === 'true' || query.approve === 'true');
const reason = body.reason || query.reason || '';
const prev = $('Send Telegram Preview').item.json;
return [{ json: { ...prev, approved, approval_reason: reason } }];

const slot = $('Parse Approval').item.json.slot;
const slots = [
  $('Globals1').item.json.PUBLISH_SLOT_1,
  $('Globals1').item.json.PUBLISH_SLOT_2,
  $('Globals1').item.json.PUBLISH_SLOT_3
];
const hhmm = slots[Math.max(0, slot - 1)] || '12:00';
const [h, m] = hhmm.split(':').map(Number);
const now = new Date();
const pub = new Date(now);
pub.setHours(h, m, 0, 0);
if (pub <= now) pub.setDate(pub.getDate() + 1);
const prev = $('Parse Approval').item.json;
return [{ json: { ...prev, publish_at_iso: pub.toISOString() }, binary: $binary }];
